/* Dashboard Gallery Widget - CSS */

/* Variables de diseño - Estilo ThingsBoard */
.dashboard-gallery-container {
    --primary-color: #305680;
    --primary-hover: #1e3a5f;
    --card-background: #ffffff;
    --text-primary: #333333;
    --text-secondary: #666666;
    --border-color: #e0e0e0;
    --shadow-sm: 0 2px 4px rgba(0, 0, 0, 0.08);
    --shadow-md: 0 4px 8px rgba(0, 0, 0, 0.12);
    --shadow-lg: 0 8px 16px rgba(0, 0, 0, 0.16);
    --border-radius: 4px;
    --transition-fast: 0.15s ease;
    --transition-normal: 0.25s ease;
    --gap: 16px;
    --columns: 3;
    --tile-width: auto;

    width: 100%;
    height: 100%;
    padding: 8px;
    box-sizing: border-box;
    background: transparent;
    font-family: Roboto, "Helvetica Neue", sans-serif;
    overflow-y: auto;
}

/* Controles del widget */
.gallery-controls {
    display: flex;
    align-items: center;
    justify-content: flex-end;
    gap: 8px;
    margin-bottom: 12px;
    padding: 4px 0;
}

.columns-label {
    font-size: 12px;
    color: var(--text-secondary);
    font-weight: 400;
}

.columns-selector {
    padding: 4px 8px;
    border: 1px solid var(--border-color);
    border-radius: 4px;
    background: var(--card-background);
    font-size: 12px;
    color: var(--text-primary);
    cursor: pointer;
    outline: none;
    min-width: 50px;
}

.columns-selector:hover {
    border-color: var(--primary-color);
}

.columns-selector:focus {
    border-color: var(--primary-color);
    box-shadow: 0 0 0 2px rgba(48, 86, 128, 0.2);
}

/* Grid de dashboards */
.dashboard-grid {
    display: grid;
    grid-template-columns: repeat(var(--columns), 1fr);
    gap: var(--gap);
    width: 100%;
}

/* Tile de dashboard */
.dashboard-tile {
    background: var(--card-background);
    border-radius: var(--border-radius);
    padding: 20px;
    cursor: pointer;
    transition: all var(--transition-normal);
    box-shadow: var(--shadow-sm);
    border: 1px solid var(--border-color);
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: flex-start;
    min-height: 140px;
    position: relative;
    overflow: hidden;
}

.dashboard-tile::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    height: 4px;
    background: linear-gradient(90deg, var(--primary-color), #42a5f5);
    transform: scaleX(0);
    transform-origin: left;
    transition: transform var(--transition-normal);
}

.dashboard-tile:hover {
    transform: translateY(-4px);
    box-shadow: var(--shadow-lg);
    border-color: var(--primary-color);
}

.dashboard-tile:hover::before {
    transform: scaleX(1);
}

.dashboard-tile:active {
    transform: translateY(-2px);
    box-shadow: var(--shadow-md);
}

/* Icono del tile */
.tile-icon {
    width: 56px;
    height: 56px;
    border-radius: 50%;
    background: linear-gradient(135deg, #e3f2fd, #bbdefb);
    display: flex;
    align-items: center;
    justify-content: center;
    margin-bottom: 12px;
    transition: all var(--transition-normal);
}

.tile-icon mat-icon {
    font-size: 28px;
    width: 28px;
    height: 28px;
    color: var(--primary-color);
}

.dashboard-tile:hover .tile-icon {
    background: linear-gradient(135deg, var(--primary-color), #42a5f5);
    transform: scale(1.1);
}

.dashboard-tile:hover .tile-icon mat-icon {
    color: white;
}

/* Imagen del tile (miniatura del dashboard) */
.tile-image {
    width: 100%;
    height: 120px;
    background-size: contain;
    background-position: center;
    background-repeat: no-repeat;
    background-color: #f0f4f8;
    border-radius: 8px;
    margin-bottom: 12px;
    flex-shrink: 0;
}

.dashboard-tile.has-image {
    padding: 12px;
    justify-content: flex-start;
    align-items: stretch;
}

.dashboard-tile.has-image .tile-content {
    text-align: center;
    margin-top: auto;
}

.dashboard-tile.has-image .tile-title {
    color: var(--text-primary);
}

.dashboard-tile.has-image .tile-description {
    color: var(--text-secondary);
}

.dashboard-tile.has-image:hover .tile-image {
    filter: brightness(1.05);
}

.dashboard-tile.has-image .shared-badge {
    z-index: 2;
}

/* Contenido del tile */
.tile-content {
    text-align: center;
    width: 100%;
}

.tile-title {
    margin: 0 0 4px 0;
    font-size: 0.95rem;
    font-weight: 600;
    color: var(--text-primary);
    overflow: hidden;
    display: -webkit-box;
    -webkit-line-clamp: 3;
    -webkit-box-orient: vertical;
    word-wrap: break-word;
    word-break: break-word;
    hyphens: auto;
    line-height: 1.3;
    max-height: calc(1.3em * 3);
}

.tile-description {
    margin: 0;
    font-size: 0.8rem;
    color: var(--text-secondary);
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
}

/* Badge para dashboards compartidos */
.shared-badge {
    position: absolute;
    top: 8px;
    right: 8px;
    background: linear-gradient(135deg, #4caf50, #66bb6a);
    color: white;
    font-size: 0.7rem;
    padding: 3px 8px;
    border-radius: 12px;
    font-weight: 500;
    text-transform: uppercase;
    letter-spacing: 0.5px;
}

/* Estados de carga */
.loading-state,
.empty-state,
.error-state {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    padding: 48px 24px;
    color: var(--text-secondary);
}

.loading-spinner {
    width: 40px;
    height: 40px;
    border: 3px solid var(--border-color);
    border-top-color: var(--primary-color);
    border-radius: 50%;
    animation: spin 1s linear infinite;
}

@keyframes spin {
    to {
        transform: rotate(360deg);
    }
}

.empty-state mat-icon,
.error-state mat-icon {
    font-size: 64px;
    width: 64px;
    height: 64px;
    margin-bottom: 16px;
    opacity: 0.5;
}

.empty-state p,
.error-state p {
    margin: 0;
    font-size: 1rem;
}

.error-state {
    color: #ef5350;
}

.error-state mat-icon {
    color: #ef5350;
}

/* Responsive adjustments */
@media (max-width: 768px) {
    .dashboard-gallery-container {
        --columns: 2 !important;
        padding: 12px;
    }

    .gallery-header {
        flex-direction: column;
        align-items: flex-start;
        gap: 12px;
    }

    .gallery-title {
        font-size: 1.25rem;
    }

    .dashboard-tile {
        min-height: 120px;
        padding: 16px;
    }

    .tile-icon {
        width: 48px;
        height: 48px;
    }

    .tile-icon mat-icon {
        font-size: 24px;
        width: 24px;
        height: 24px;
    }
}

@media (max-width: 480px) {
    .dashboard-gallery-container {
        --columns: 1 !important;
    }
}

