self.onInit = function () {
    self.$container = self.ctx.$container;
    self.dashboardGrid = self.$container.find('#dashboardGrid');
    self.loadingState = self.$container.find('#loadingState');
    self.emptyState = self.$container.find('#emptyState');
    self.errorState = self.$container.find('#errorState');
    self.errorMessage = self.$container.find('#errorMessage');
    self.container = self.$container.find('.dashboard-gallery-container');

    self.settings = {
        minTileWidth: parseInt(self.ctx.settings.minTileWidth) || 180,
        maxTileWidth: parseInt(self.ctx.settings.maxTileWidth) || 350,
        tileGap: parseInt(self.ctx.settings.tileGap) || 16,
        showDescription: self.ctx.settings.showDescription === true,
        backgroundColor: self.ctx.settings.backgroundColor || '',
        tileBackgroundColor: self.ctx.settings.tileBackgroundColor || '',
        imageBackgroundColor: self.ctx.settings.imageBackgroundColor || '',
        tileBorderRadius: self.ctx.settings.tileBorderRadius || 5,
        hoverBarColor: self.ctx.settings.hoverBarColor || '',
        titleFont: self.ctx.settings.titleFont || null,
        titleColor: self.ctx.settings.titleColor || '',
        hideCurrentDashboard: self.ctx.settings.hideCurrentDashboard !== false
    };

    self.userAuthority = null;
    self.currentDashboardId = null;

    if (self.ctx.dashboard) {
        if (self.ctx.dashboard.dashboardId) {
            self.currentDashboardId = self.ctx.dashboard.dashboardId;
        } else if (self.ctx.dashboard.id) {
            self.currentDashboardId = self.ctx.dashboard.id.id || self.ctx.dashboard.id;
        }
    }

    if (!self.currentDashboardId && self.ctx.stateController) {
        var sc = self.ctx.stateController;
        if (sc.dashboardId) {
            self.currentDashboardId = sc.dashboardId.id || sc.dashboardId;
        }
        if (!self.currentDashboardId && sc.route && sc.route.snapshot && sc.route.snapshot.params) {
            if (sc.route.snapshot.params.dashboardId) {
                self.currentDashboardId = sc.route.snapshot.params.dashboardId;
            }
        }
    }

    if (!self.currentDashboardId) {
        var url = window.location.pathname;
        var match = url.match(/([a-f0-9]{8}-[a-f0-9]{4}-[a-f0-9]{4}-[a-f0-9]{4}-[a-f0-9]{12})/i);
        if (match && match[1]) {
            self.currentDashboardId = match[1];
        }
    }

    if (self.settings.backgroundColor) {
        self.container.css('background-color', self.settings.backgroundColor);
    }

    if (self.settings.hoverBarColor) {
        var styleId = 'dashboard-gallery-hover-style';
        if (self.$container.find('#' + styleId).length === 0) {
            var customStyle = $('<style id="' + styleId + '"></style>');
            customStyle.text('.dashboard-tile::before { background: ' + self.settings.hoverBarColor + ' !important; }');
            self.$container.append(customStyle);
        }
    }

    self.$container.find('.gallery-controls').hide();
    self.initResponsiveLayout();
    self.loadDashboards();
};

self.initResponsiveLayout = function () {
    self.calculateResponsiveLayout();
    if (typeof ResizeObserver !== 'undefined') {
        self.resizeObserver = new ResizeObserver(function () {
            self.calculateResponsiveLayout();
        });
        self.resizeObserver.observe(self.container[0]);
    } else {
        $(window).on('resize.dashboardGallery', function () {
            self.calculateResponsiveLayout();
        });
    }
};

self.calculateResponsiveLayout = function () {
    var containerWidth = self.container.width();
    if (!containerWidth || containerWidth < 50) return;

    var minWidth = self.settings.minTileWidth;
    var maxWidth = self.settings.maxTileWidth;
    var baseGap = self.settings.tileGap;

    var maxColumns = Math.floor((containerWidth + baseGap) / (minWidth + baseGap));
    maxColumns = Math.max(1, maxColumns);

    var totalGapWidth = (maxColumns - 1) * baseGap;
    var tileWidth = (containerWidth - totalGapWidth) / maxColumns;

    var gap = baseGap;
    if (tileWidth > maxWidth) {
        var excessWidth = (tileWidth - maxWidth) * maxColumns;
        var additionalGapPerSpace = excessWidth / Math.max(1, maxColumns + 1);
        gap = baseGap + additionalGapPerSpace;
        tileWidth = maxWidth;
    }

    self.container.css({
        '--columns': maxColumns,
        '--gap': gap + 'px',
        '--tile-width': tileWidth + 'px'
    });
};

self.loadDashboards = function () {
    self.showLoading();

    var user = self.ctx.currentUser;
    if (!user) {
        self.showError('No se pudo obtener información del usuario');
        return;
    }

    self.userAuthority = user.authority;

    if (user.authority === 'TENANT_ADMIN') {
        // Tenant: cargar todos los dashboards directo
        self.ctx.http.get('/api/tenant/dashboards?pageSize=100&page=0').subscribe(
            function (response) {
                self.handleDashboardsResponse(response, null);
            },
            function (error) {
                console.error('Error loading tenant dashboards:', error);
                self.showError('Error al cargar los dashboards');
            }
        );

    } else if (user.authority === 'CUSTOMER_USER') {
        var customerId = user.customerId
            ? (user.customerId.id || user.customerId)
            : null;
        var userId = user.userId
            ? (user.userId.id || user.userId)
            : (user.id ? (user.id.id || user.id) : null);

        if (!customerId) {
            self.showError('No se pudo obtener el customerId del usuario');
            return;
        }

        // Cargar dashboards y atributos del usuario en paralelo
        Promise.all([
            self.ctx.http.get('/api/customer/' + customerId + '/dashboards?pageSize=100&page=0').toPromise(),
            self.ctx.http.get('/api/plugins/telemetry/USER/' + userId + '/values/attributes/SERVER_SCOPE').toPromise()
        ]).then(function (results) {
            var dashboardsResponse = results[0];
            var attributes = results[1] || [];

            // Convertir array de atributos a mapa clave/valor
            var attrMap = {};
            attributes.forEach(function (a) { attrMap[a.key] = a.value; });

            var allowedIds = null;

            if (attrMap.dashboardAccess === 'restricted') {
                allowedIds = Array.isArray(attrMap.allowedDashboards)
                    ? attrMap.allowedDashboards
                    : [];
            }
            // Si dashboardAccess === 'all' o no existe el atributo → allowedIds queda null → muestra todo

            self.handleDashboardsResponse(dashboardsResponse, allowedIds);

        }).catch(function (error) {
            console.error('Error loading customer data:', error);
            self.showError('Error al cargar los dashboards');
        });

    } else {
        self.showError('Tipo de usuario no soportado');
    }
};

// allowedIds: null = mostrar todos | array = filtrar solo esos IDs
self.handleDashboardsResponse = function (response, allowedIds) {
    var dashboards = [];

    if (response && response.data) {
        dashboards = response.data;
    } else if (Array.isArray(response)) {
        dashboards = response;
    }

    // Filtrar por acceso restringido
    if (allowedIds !== null) {
        dashboards = dashboards.filter(function (d) {
            var dId = d.id ? (d.id.id || d.id) : null;
            return allowedIds.indexOf(dId) !== -1;
        });
    }

    // Filtrar dashboard actual
    if (self.settings.hideCurrentDashboard && self.currentDashboardId) {
        dashboards = dashboards.filter(function (d) {
            var dId = d.id ? (d.id.id || d.id) : null;
            return dId !== self.currentDashboardId;
        });
    }

    dashboards.sort(function (a, b) {
        var nameA = (a.name || a.title || '').toLowerCase();
        var nameB = (b.name || b.title || '').toLowerCase();
        return nameA.localeCompare(nameB);
    });

    if (dashboards.length === 0) {
        self.showEmpty();
        return;
    }

    self.renderDashboards(dashboards);
};

self.renderDashboards = function (dashboards) {
    self.hideAllStates();
    self.dashboardGrid.empty();

    dashboards.forEach(function (dashboard) {
        try {
            var tile = self.createDashboardTile(dashboard);
            self.dashboardGrid.append(tile);
        } catch (err) {
            console.error('[Gallery] Error creating tile:', err, dashboard);
        }
    });

    self.dashboardGrid.show();
};

self.createDashboardTile = function (dashboard) {
    var id = dashboard.id ? (dashboard.id.id || dashboard.id) : null;
    var name = dashboard.name || dashboard.title || 'Sin nombre';
    var description = dashboard.configuration && dashboard.configuration.description
        ? dashboard.configuration.description
        : '';

    // Badge "compartido" solo visible para tenant admin
    var isShared = self.userAuthority === 'TENANT_ADMIN'
        && dashboard.assignedCustomers
        && dashboard.assignedCustomers.length > 0;

    var imageUrl = self.getImageUrl(dashboard.image);
    var defaultImageUrl = '/api/images/public/70fbiSBhPGbssBDr9CDtgi1Gh3psN8ZB';

    var tile = $('<div class="dashboard-tile"></div>');
    tile.attr('data-dashboard-id', id);

    if (isShared) {
        tile.append('<span class="shared-badge">Compartido</span>');
    }

    var imageContainer = $('<div class="tile-image"></div>');

    if (self.settings.imageBackgroundColor) {
        imageContainer.css('background-color', self.settings.imageBackgroundColor);
    }

    tile.append(imageContainer);
    tile.addClass('has-image');

    if (self.settings.tileBackgroundColor) {
        tile.css('background-color', self.settings.tileBackgroundColor);
    }

    if (self.settings.tileBorderRadius !== undefined) {
        var radius = self.settings.tileBorderRadius + '%';
        tile.css('border-radius', radius);
        imageContainer.css('border-radius', radius);
    }

    if (imageUrl) {
        self.loadImageWithAuth(imageUrl, imageContainer);
    } else {
        imageContainer.css('background-image', 'url(' + defaultImageUrl + ')');
    }

    var content = $('<div class="tile-content"></div>');
    var titleElement = $('<h3 class="tile-title" title="' + self.escapeHtml(name) + '">' + self.escapeHtml(name) + '</h3>');

    if (self.settings.titleFont) {
        var font = self.settings.titleFont;
        if (font.family) titleElement.css('font-family', font.family);
        if (font.size) titleElement.css('font-size', font.size + font.sizeUnit);
        if (font.style === 'italic') titleElement.css('font-style', 'italic');
        if (font.weight) titleElement.css('font-weight', font.weight);
    }

    if (self.settings.titleColor) {
        titleElement.css('color', self.settings.titleColor);
    }

    content.append(titleElement);

    if (self.settings.showDescription && description) {
        content.append('<p class="tile-description" title="' + self.escapeHtml(description) + '">' + self.escapeHtml(description) + '</p>');
    }

    tile.append(content);

tile.on('click', function () {
    var clickedId = $(this).attr('data-dashboard-id');
    var clickedName = $(this).find('.tile-title').text();
    self.navigateToDashboard(clickedId, clickedName);
});

    return tile;
};

self.loadImageWithAuth = function (imageUrl, container) {
    self.ctx.http.get(imageUrl, { responseType: 'blob' }).subscribe(
        function (blob) {
            var reader = new FileReader();
            reader.onloadend = function () {
                container.css('background-image', 'url(' + reader.result + ')');
            };
            reader.readAsDataURL(blob);
        },
        function (error) {
            container.html('<mat-icon style="font-size:48px;color:#ccc;">image_not_supported</mat-icon>');
            container.css({ display: 'flex', 'align-items': 'center', 'justify-content': 'center', 'background-color': '#f5f5f5' });
        }
    );
};

self.getImageUrl = function (image) {
    if (!image) return null;
    if (image.startsWith('http://') || image.startsWith('https://') || image.startsWith('data:')) return image;
    if (image.startsWith('tb-image;')) return image.substring(9);
    if (image.startsWith('tb-image:')) {
        var parts = image.substring(9);
        if (parts.startsWith('sys;')) return '/api/images/system/' + encodeURIComponent(parts.substring(4));
        return '/api/images/tenant/' + encodeURIComponent(parts);
    }
    if (image.startsWith('/api/') || image.startsWith('/')) return image;
    return '/api/images/tenant/' + encodeURIComponent(image);
};

self.navigateToDashboard = function (dashboardId) {
    var basePath = window.location.pathname;
    basePath = basePath.substring(0, basePath.lastIndexOf('/'));
    self.ctx.router.navigateByUrl(basePath + '/' + dashboardId);
};


self.escapeHtml = function (text) {
    if (!text) return '';
    var div = document.createElement('div');
    div.textContent = text;
    return div.innerHTML;
};

self.showLoading = function () {
    self.dashboardGrid.hide();
    self.emptyState.hide();
    self.errorState.hide();
    self.loadingState.show();
};

self.showEmpty = function () {
    self.loadingState.hide();
    self.dashboardGrid.hide();
    self.errorState.hide();
    self.emptyState.show();
};

self.showError = function (message) {
    self.loadingState.hide();
    self.dashboardGrid.hide();
    self.emptyState.hide();
    self.errorMessage.text(message);
    self.errorState.show();
};

self.hideAllStates = function () {
    self.loadingState.hide();
    self.emptyState.hide();
    self.errorState.hide();
};

self.onDataUpdated = function () {};

self.onResize = function () {
    self.calculateResponsiveLayout();
};

self.onDestroy = function () {
    if (self.resizeObserver) self.resizeObserver.disconnect();
    $(window).off('resize.dashboardGallery');
};

